import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

// Behavior under test (from src/merge.js doc comment):
//   - overlapping intervals are merged ([1,4],[3,6] -> [1,6])
//   - touching intervals are merged ([1,2],[2,3] -> [1,3])
//   - disjoint intervals stay separate
//   - [] -> []
//   - result sorted by start ascending
//   - input array and its pairs are never mutated
//   - throws RangeError if any pair has start > end
//
// Each test names the concrete bug it would catch.

describe("empty / trivial inputs", () => {
  it("[] -> []", () => {
    // Bug: crashing or returning non-empty on empty input.
    expect(mergeIntervals([])).toEqual([]);
  });

  it("single interval passes through unchanged", () => {
    // Bug: dropping or altering a lone interval.
    expect(mergeIntervals([[3, 7]])).toEqual([[3, 7]]);
  });
});

describe("overlapping intervals are merged", () => {
  it("merges the documented [1,4],[3,6] -> [1,6]", () => {
    // Bug: failing to extend the running interval on overlap.
    expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
  });

  it("keeps the larger end when the second interval is fully contained", () => {
    // Bug: using `end` instead of Math.max(last[1], end) would shrink
    // [1,10] down to [1,3] when [2,3] is absorbed.
    expect(mergeIntervals([[1, 10], [2, 3]])).toEqual([[1, 10]]);
  });

  it("chains a run of three overlapping intervals into one", () => {
    // Bug: only comparing against the raw previous input, not the
    // accumulated merged end.
    expect(mergeIntervals([[1, 3], [2, 5], [4, 8]])).toEqual([[1, 8]]);
  });
});

describe("touching vs disjoint boundary (last.end vs next.start)", () => {
  it("merges when next.start === last.end (touching, at the boundary)", () => {
    // Bug: using `start < last[1]` instead of `<=` would leave
    // [1,2],[2,3] as two intervals.
    expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
  });

  it("merges when next.start === last.end - 1 (overlap, just below boundary)", () => {
    // Bug: an off-by-one that treats a 1-unit overlap as disjoint.
    expect(mergeIntervals([[1, 3], [2, 4]])).toEqual([[1, 4]]);
  });

  it("keeps separate when next.start === last.end + 1 (gap of 1, just above boundary)", () => {
    // Bug: using `start <= last[1] + 1` (treating adjacency as touching)
    // would wrongly merge [1,2],[3,4].
    expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
  });
});

describe("disjoint intervals stay separate", () => {
  it("keeps well-separated intervals apart and in order", () => {
    // Bug: over-eager merging that collapses unrelated intervals.
    expect(mergeIntervals([[1, 2], [5, 6], [9, 10]])).toEqual([
      [1, 2],
      [5, 6],
      [9, 10],
    ]);
  });
});

describe("sorting by start ascending", () => {
  it("sorts unsorted input before merging", () => {
    // Bug: merging without sorting would leave [5,6] before [1,3]
    // and miss that [2,4] overlaps [1,3].
    expect(mergeIntervals([[5, 6], [1, 3], [2, 4]])).toEqual([
      [1, 4],
      [5, 6],
    ]);
  });

  it("merges an overlap that is only adjacent after sorting", () => {
    // Bug: no sort — [3,9] and [1,4] never get compared, so the
    // overlap is missed.
    expect(mergeIntervals([[3, 9], [1, 4]])).toEqual([[1, 9]]);
  });

  it("sorts negative and mixed-sign starts correctly", () => {
    // Bug: string/lexicographic sort would order -5 after 0.
    expect(mergeIntervals([[0, 1], [-5, -3], [-1, 2]])).toEqual([
      [-5, -3],
      [-1, 2],
    ]);
  });
});

describe("duplicates and identical starts", () => {
  it("collapses identical duplicate intervals into one", () => {
    // Bug: emitting duplicates instead of merging equal intervals.
    expect(mergeIntervals([[2, 4], [2, 4]])).toEqual([[2, 4]]);
  });

  it("takes the widest end among intervals sharing a start", () => {
    // Bug: keeping the first (narrower) interval [1,3] instead of [1,7].
    expect(mergeIntervals([[1, 3], [1, 7]])).toEqual([[1, 7]]);
  });
});

describe("zero-width intervals (start === end)", () => {
  it("does not throw for a point interval and preserves it", () => {
    // Bug: treating start === end as invalid (start > end check too strict).
    expect(mergeIntervals([[5, 5]])).toEqual([[5, 5]]);
  });

  it("merges a point interval that touches a range endpoint", () => {
    // Bug: point [3,3] touching [1,3] left separate.
    expect(mergeIntervals([[1, 3], [3, 3]])).toEqual([[1, 3]]);
  });
});

describe("invalid input throws RangeError", () => {
  it("throws RangeError when a pair has start > end", () => {
    // Bug: silently accepting or normalizing a reversed interval.
    expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
  });

  it("throws even when only one of several pairs is reversed", () => {
    // Bug: only validating the first element.
    expect(() => mergeIntervals([[1, 2], [8, 3], [4, 5]])).toThrow(RangeError);
  });

  it("throws for start exactly one greater than end (boundary)", () => {
    // Bug: off-by-one in the validation (`start >= end` vs `start > end`)
    // would either miss [3,2] or wrongly reject [3,3].
    expect(() => mergeIntervals([[3, 2]])).toThrow(RangeError);
  });
});

describe("immutability", () => {
  it("does not mutate the input array", () => {
    // Bug: sorting/merging in place would reorder or shrink the caller's array.
    const input = [[5, 6], [1, 3], [2, 4]];
    mergeIntervals(input);
    expect(input).toEqual([[5, 6], [1, 3], [2, 4]]);
  });

  it("does not mutate the inner pair objects", () => {
    // Bug: `last[1] = ...` writing through to a shared input pair would
    // change the caller's [1,3] into [1,4].
    const pair = [1, 3];
    const input = [pair, [2, 4]];
    mergeIntervals(input);
    expect(pair).toEqual([1, 3]);
  });

  it("returns a new array distinct from the input", () => {
    // Bug: returning the same array reference the caller passed in.
    const input = [[1, 2]];
    expect(mergeIntervals(input)).not.toBe(input);
  });
});

